previewCss:
.darma-loader-uiverse-notification-pulse-bell {
  width: fit-content;
  height: fit-content;
  background-color: var(--loader-secondary-color, #3a3a3a);
  border-radius: 7px;
  padding: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  cursor: pointer;
  transition: 0.2s;
}

.darma-loader-uiverse-notification-pulse-bell:hover {
background-color: rgb(26, 26, 26);
}

.darma-loader-uiverse-notification-pulse-bell:hover svg {
color: white;
}

.darma-loader-uiverse-notification-pulse-bell svg {
color: rgba(255, 255, 255, 0.651);
transform: scale(1.2);
transition: 0.2s;
}

.darma-loader-uiverse-notification-pulse-bell__point {
position: absolute;
bottom: 5px;
left: 5px;
width: 6px;
height: 6px;
background-color: var(--loader-color, #00ff00);
border-radius: 25px;
display: flex;
align-items: center;
justify-content: center;
}

.darma-loader-uiverse-notification-pulse-bell__point::before {
content: "";
position: absolute;
width: 1px;
height: 1px;
background-color: var(--loader-color, #00ff00);
border-radius: 25px;
animation: darma-loader-uiverse-notification-pulse-bell-loop 1s 0s infinite;
}

@keyframes darma-loader-uiverse-notification-pulse-bell-loop {
0% {
background-color: var(--loader-color, #00ff00);
width: 1px;
height: 1px;
}
100% {
background-color: transparent;
width: 30px;
height: 30px;
}
}

